class Solution:
    def maxSlidingWindow(self, nums, k):
        from collections import deque
        dq = deque()
        res = []
        for i, v in enumerate(nums):
            while dq and nums[dq[-1]] <= v:
                dq.pop()
            dq.append(i)
            if dq[0] <= i - k:
                dq.popleft()
            if i >= k - 1:
                res.append(nums[dq[0]])
        return res

